// Ana tırtıl SVG bileşeni
// Tüm bölge bileşenlerini ve defs'i bir araya getirir.
// Props:
//   activeZone (string | null) – "front" | "mid" | "back" | null
//   isEyesClosed (boolean)

import CaterpillarDefs from "./CaterpillarDefs";
import BackZone from "./BackZone";
import MidZone from "./MidZone";
import FrontZone from "./FrontZone";

export default function CaterpillarSVG({ activeZone, eyeState }) {
  return (
    <svg
      viewBox="0 0 560 230"
      xmlns="http://www.w3.org/2000/svg"
      overflow="visible"
      style={{
        width: "min(560px, 92vw)",
        height: "auto",
        overflow: "visible",
        filter: "drop-shadow(0 12px 28px rgba(80,120,80,0.18))",
      }}
    >
      <CaterpillarDefs />

      {/* Zemin gölgesi */}
      <ellipse cx="270" cy="216" rx="220" ry="10" fill="url(#c-shadowGrad)" />

      {/* Bölgeler: arka → orta → ön sıralamasıyla çizilir (z-order) */}
      <BackZone isActive={activeZone === "back"} />
      <MidZone isActive={activeZone === "mid"} />
      <FrontZone isActive={activeZone === "front"} eyeState={eyeState} />
    </svg>
  );
}
