// Tırtılın ÖN bölgesi – boyun + kafa + yüz
// Props:
//   isActive (bool) – bölge aydınlanmış mı?

import { useState, useEffect } from "react";

export default function FrontZone({ isActive, eyeState }) {
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const handleMouseMove = (e) => {
      // Ekran genişliğine göre -1 ile +1 arası normalize x ve y koordinatı
      const x = (e.clientX / window.innerWidth) * 2 - 1;
      const y = (e.clientY / window.innerHeight) * 2 - 1;
      setMousePos({ x, y });
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const eyeStyle = {
    transform: `translate(${mousePos.x * 4.5}px, ${mousePos.y * 4.5}px)`,
    transition: "transform 0.1s ease-out",
  };

  const isLeftClosed = eyeState === "closed";
  const isRightClosed = eyeState === "closed" || eyeState === "peeking";

  return (
    <g className={`lk-head-group${isActive ? " bobbing" : ""}`}>
      {/* Boyun segmenti  r=47 */}
      <circle cx="340" cy="123" r="47" fill="url(#c-seg)" />
      <circle cx="340" cy="123" r="47" fill="url(#c-segHi)" />

      {/* Kafa  r=62 */}
      <circle cx="416" cy="108" r="62" fill="url(#c-headGrad)" />
      <circle cx="416" cy="108" r="62" fill="url(#c-segHi)" />

      {/* Yanak pembesi */}
      <ellipse cx="382" cy="126" rx="15" ry="10" fill="#e07070" opacity="0.32" />
      <ellipse cx="448" cy="122" rx="13" ry="9" fill="#e07070" opacity="0.28" />

      {/* Sol göz */}
      <g className={isLeftClosed ? "" : "lk-eye-blink"} style={{ transformOrigin: "400px 97px" }}>
        <circle cx="400" cy="97" r="15" fill={isLeftClosed ? "#d46868" : "white"} style={{ transition: "fill 0.2s ease" }} />
        <g style={{ ...eyeStyle, opacity: isLeftClosed ? 0 : 1, transition: "opacity 0.15s ease" }}>
          <circle cx="402" cy="98" r="9" fill="#5c2e1a" />
          <circle cx="405" cy="94" r="4" fill="white" opacity="0.85" />
        </g>
        {/* Kapalı göz kirpik/kıvrım çizgisi */}
        <path d="M 388 98 Q 400 102 411 98" fill="none" stroke="#5c2e1a" strokeWidth="2.5" strokeLinecap="round" style={{ opacity: isLeftClosed ? 0.6 : 0, transition: "opacity 0.2s ease" }} />
      </g>

      {/* Sağ göz */}
      <g className={isRightClosed ? "" : "lk-eye-blink"} style={{ transformOrigin: "432px 94px", animationDelay: "0.18s" }}>
        <circle cx="432" cy="94" r="15" fill={isRightClosed ? "#d46868" : "white"} style={{ transition: "fill 0.2s ease" }} />
        <g style={{ ...eyeStyle, opacity: isRightClosed ? 0 : 1, transition: "opacity 0.15s ease" }}>
          <circle cx="434" cy="95" r="9" fill="#5c2e1a" />
          <circle cx="437" cy="91" r="4" fill="white" opacity="0.85" />
        </g>
        {/* Kapalı göz kirpik/kıvrım çizgisi */}
        <path d="M 420 95 Q 432 99 443 95" fill="none" stroke="#5c2e1a" strokeWidth="2.5" strokeLinecap="round" style={{ opacity: isRightClosed ? 0.6 : 0, transition: "opacity 0.2s ease" }} />
      </g>

      {/* Kaşlar */}
      <path d="M 391 85 Q 400 80 409 85" fill="none" stroke="#c06040" strokeWidth="2.2" strokeLinecap="round" opacity="0.55" />
      <path d="M 423 82 Q 432 77 441 82" fill="none" stroke="#c06040" strokeWidth="2.2" strokeLinecap="round" opacity="0.55" />

      {/* Burun */}
      <circle cx="416" cy="113" r="4.5" fill="#c86050" opacity="0.45" />

      {/* Gülümseme */}
      <path d="M 398 124 Q 416 141 434 124" fill="none" stroke="#c06050" strokeWidth="3" strokeLinecap="round" opacity="0.65" />

      {/* Neon glow overlay */}
      <g className={`lk-glow${isActive ? " lit" : ""}`}>
        <ellipse cx="385" cy="116" rx="88" ry="66" fill="url(#c-lampF)" filter="url(#c-glowF)" />
      </g>

      {/* Bölge halkası */}
      <ellipse
        cx="385" cy="116" rx="94" ry="72"
        className={`lk-zone-ring${isActive ? " lit" : ""}`}
        stroke="#ffd740"
      />
    </g>
  );
}
