// Kök uygulama bileşeni
// AppProvider'ı sarar ve activeScreen'e göre ekranı seçer.

import React, { useEffect, useState } from 'react';
import { AppProvider, useApp } from "./context/AppContext";
import Home from "./screens/Home";
import WordList from "./screens/WordList";
import GameScreen from "./screens/GameScreen";
import GameModeSingle from "./screens/GameModeSingle";
import InstructionalPage from "./screens/InstructionalPage";
import HowToUse from "./screens/HowToUse";
import { auth, db } from './firebaseConfig';
import { onAuthStateChanged, signOut, updateProfile } from 'firebase/auth';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import Register from './components/Register';
import Login from './components/Login';
import ResetPassword from './components/ResetPassword';
import CaterpillarSVG from './components/CaterpillarSVG';
import Background from './components/Background';

function Router() {
  const { activeScreen } = useApp();
  if (activeScreen === "wordList") return <WordList />;
  if (activeScreen === "game") return <GameScreen />;
  if (activeScreen === "gameSingle") return <GameModeSingle />;
  if (activeScreen === "instructional") return <InstructionalPage />;
  if (activeScreen === "howToUse") return <HowToUse />;
  return <Home />;
}

// Sadece ana sayfada görünecek sağ üst kullanıcı/çıkış rozeti
function TopRightBadge({ user, handleLogout, onEditProfile }) {
  const { activeScreen } = useApp();
  const [isBadgeOpen, setIsBadgeOpen] = useState(false);

  // Uygulama ilk açıldığında veya home ekranındayken activeScreen "home" olur
  if (activeScreen && activeScreen !== "home") return null;

  return (
    <div className={`auth-badge ${isBadgeOpen ? 'open' : ''}`} onClick={() => setIsBadgeOpen(!isBadgeOpen)}>
      <div className="auth-badge__icon" title="Ayarlar / Çıkış">👤</div>
      <div className="auth-badge__content">
        <span
          className="auth-badge__email"
          title="İsmi Düzenle"
          onClick={(e) => {
            e.stopPropagation();
            onEditProfile();
          }}
        >
          {user?.displayName || user?.email}
        </span>
        <button
          className="auth-badge__btn"
          onClick={(e) => {
            e.stopPropagation();
            handleLogout();
          }}
        >
          Çıkış
        </button>
      </div>
    </div>
  );
}

// Profil İsmini Düzenleme Popup'ı
function ProfileModal({ user, onClose, onUpdateName }) {
  const [name, setName] = useState(user?.displayName || "");
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    if (!name.trim()) return;
    setIsSaving(true);
    try {
      await updateProfile(auth.currentUser, { displayName: name.trim() });
      onUpdateName(name.trim());
      onClose();
    } catch (err) {
      alert("İsim güncellenirken bir hata oluştu: " + err.message);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="modal-overlay" style={{ zIndex: 10000 }}>
      <div className="modal" style={{ maxWidth: '380px', textAlign: 'center' }}>
        <h2 className="modal__title" style={{ justifyContent: 'center' }}>Profili Düzenle</h2>

        <div style={{ marginBottom: "20px" }}>
          <p style={{ fontSize: "0.82rem", color: "#7aaa8a", fontWeight: "800", marginBottom: "6px", textTransform: "uppercase", letterSpacing: "0.5px" }}>Hesap (E-posta)</p>
          <div style={{ background: "#f0f4f1", padding: "10px", borderRadius: "14px", color: "#2d4a38", fontWeight: "800", fontSize: "0.95rem" }}>
            {user?.email}
          </div>
        </div>

        <div style={{ marginBottom: "20px" }}>
          <p style={{ fontSize: "0.82rem", color: "#7aaa8a", fontWeight: "800", marginBottom: "6px", textTransform: "uppercase", letterSpacing: "0.5px" }}>Ad Soyad</p>
          <input
            type="text"
            className="modal__input"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="İsminizi girin..."
            style={{ width: "100%", textAlign: "center", fontSize: "1.1rem" }}
            autoFocus
          />
        </div>

        <div className="modal__actions">
          <button className="modal__btn modal__btn--cancel" onClick={onClose} disabled={isSaving}>
            Geri
          </button>
          <button className="modal__btn modal__btn--save" onClick={handleSave} disabled={isSaving || !name.trim()}>
            {isSaving ? "Kaydediliyor..." : "Kaydet"}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isLoginView, setIsLoginView] = useState(true);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [eyeState, setEyeState] = useState("open"); // "open" | "closed" | "peeking"
  const [oobCode, setOobCode] = useState(null);

  useEffect(() => {
    // URL'den olası Firebase kodunu yakalama
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('oobCode');
    if (code) {
      setOobCode(code);
    }

    // Firebase'in arka planda ürettiği zararsız "AbortError" konsol hatalarını gizle
    const handleUnhandledRejection = (event) => {
      if (event.reason && event.reason.name === 'AbortError') {
        event.preventDefault(); // Konsola hata basılmasını (Uncaught in promise) engeller
      }
    };
    window.addEventListener('unhandledrejection', handleUnhandledRejection);

    // Kullanıcı oturum durumunu dinle
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setLoading(false);
    });

    // Component unmount olduğunda dinleyiciyi temizle
    return () => {
      unsubscribe();
      window.removeEventListener('unhandledrejection', handleUnhandledRejection);
    };
  }, []);

  const handleLogout = async () => {
    try {
      await signOut(auth); // Tamamlanmasını bekle
      console.log("Çıkış yapıldı");
    } catch (error) {
      if (error.code !== 'auth/user-cancelled') { // Kullanıcı bazlı iptalleri görmezden gel
        console.error("Çıkış hatası:", error);
      }
    }
  };

  const handleUpdateName = (newName) => {
    setUser((prev) => {
      if (!prev) return null;
      // React'ın state değişikliğini algılaması için yeni bir nesne kopyası oluşturuyoruz
      const updatedUser = Object.assign({}, prev);
      updatedUser.displayName = newName;
      return updatedUser;
    });
  };

  if (loading) {
    return <div style={{ padding: '20px', textAlign: 'center', fontFamily: "'Baloo 2', cursive", fontSize: "1.5rem", color: "#2d4a38" }}>Yükleniyor...</div>;
  }

  return (
    <div style={{ width: '100%', height: '100%' }}>
      {user ? (
        <>
          {/* Ana Uygulama */}
          <AppProvider>
            <TopRightBadge
              user={user}
              handleLogout={handleLogout}
              onEditProfile={() => setShowProfileModal(true)}
            />
            <Router />
          </AppProvider>

          {showProfileModal && (
            <ProfileModal
              user={user}
              onClose={() => setShowProfileModal(false)}
              onUpdateName={handleUpdateName}
            />
          )}
        </>
      ) : (
        <div className="screen" style={{ justifyContent: 'center', padding: '10px 0' }}>
          <Background />
          <div style={{ position: "relative", zIndex: 5, marginBottom: -20, transform: "scale(0.88)" }}>
            <CaterpillarSVG activeZone={null} eyeState={eyeState} />
          </div>
          <div className="modal" style={{ maxWidth: '420px', margin: '0 auto', textAlign: 'center', position: 'relative', zIndex: 10 }}>
            <h1 className="home__hero-title" style={{ fontSize: '2rem', marginBottom: '16px' }}>Lingual Kontrol</h1>

            {oobCode ? (
              <ResetPassword oobCode={oobCode} onBackToLogin={() => setOobCode(null)} onEyeStateChange={setEyeState} />
            ) : isLoginView ? (
              <Login onEyeStateChange={setEyeState} /> 
            ) : (
              <Register onEyeStateChange={setEyeState} />
            )}

            {!oobCode && (
              <div style={{ marginTop: '16px', paddingTop: '12px', borderTop: '2px dashed #e4f1e9', fontSize: '0.95rem' }}>
                <span style={{ color: '#5a9a6a', fontWeight: '700' }}>
                  {isLoginView ? "Hesabın yok mu?" : "Zaten hesabın var mı?"}
                </span>
                <button
                  onClick={() => setIsLoginView(!isLoginView)}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: '#2ecc71',
                    fontFamily: "'Nunito', sans-serif",
                    fontWeight: '800',
                    fontSize: '0.95rem',
                    cursor: 'pointer',
                    marginLeft: '8px',
                    textDecoration: 'underline'
                  }}
                >
                  {isLoginView ? "Kayıt Ol" : "Giriş Yap"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
