import React, { useState } from 'react';
import { auth } from '../firebaseConfig';
import { createUserWithEmailAndPassword, updateProfile } from 'firebase/auth';

const Register = ({ onEyeStateChange }) => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleRegister = async (e) => {
    if (e) e.preventDefault();
    setError('');
    setIsSubmitting(true);
    try {
      // 1. Firebase Authentication'da kullanıcıyı oluştur
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);

      // 2. Kullanıcının girdiği İsmi doğrudan (veritabanı kullanmadan) Auth profiline kaydet
      if (name) {
        await updateProfile(userCredential.user, { displayName: name });
        window.location.reload();
      }
    } catch (error) {
      console.error("Kayıt hatası:", error.message);
      setError("Kayıt başarısız. " + (error.message.includes('email-already-in-use') ? "Bu e-posta zaten kullanımda." : "Lütfen bilgilerinizi kontrol edin."));
      setIsSubmitting(false); // Hata durumunda butonu tekrar aktif et
    }
  };

  const handleKeyDown = (e) => {
    // Enter tuşuna basıldığında formu yollaması için
    if (e.key === 'Enter') handleRegister(e);
  }

  return (
    <div onKeyDown={handleKeyDown} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
      <h2 style={{ fontFamily: "'Baloo 2', cursive", fontSize: '1.4rem', color: '#2d6e40', marginBottom: '8px' }}>Yeni Hesap Oluştur</h2>

      {error && <div style={{ color: '#eb4d4b', fontSize: '0.85rem', fontWeight: '700', marginBottom: '8px', background: '#ffecec', padding: '8px', borderRadius: '8px' }}>{error}</div>}

      <input className="modal__input" type="text" placeholder="Ad Soyad" value={name} onChange={(e) => setName(e.target.value)} required disabled={isSubmitting} onFocus={() => { if (onEyeStateChange) onEyeStateChange("open"); }} />
      <input className="modal__input" type="email" placeholder="E-posta Adresi" value={email} onChange={(e) => setEmail(e.target.value)} required disabled={isSubmitting} onFocus={() => { if (onEyeStateChange) onEyeStateChange("open"); }} />
      
      <div style={{ position: 'relative', width: '100%' }}>
        <input 
          className="modal__input" 
          type={showPassword ? "text" : "password"} 
          placeholder="Şifre (En az 6 karakter)" 
          value={password} 
          onChange={(e) => setPassword(e.target.value)} 
          onFocus={() => { if (onEyeStateChange) onEyeStateChange(showPassword ? "peeking" : "closed"); }}
          onBlur={() => { if (onEyeStateChange) onEyeStateChange("open"); }}
          required 
          minLength={6} 
          disabled={isSubmitting} 
          style={{ paddingRight: '45px' }}
        />
        <button
          type="button"
          disabled={isSubmitting}
          onClick={() => {
            const nextState = !showPassword;
            setShowPassword(nextState);
            if (onEyeStateChange) onEyeStateChange(nextState ? "peeking" : "closed");
          }}
          style={{
            position: 'absolute',
            right: '12px',
            top: '50%',
            transform: 'translateY(-50%)',
            background: 'none',
            border: 'none',
            cursor: isSubmitting ? 'default' : 'pointer',
            fontSize: '1.2rem',
            padding: '2px',
            opacity: isSubmitting ? 0.3 : 0.6,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}
          title={showPassword ? "Şifreyi Gizle" : "Şifreyi Göster"}
        >
          {showPassword ? "🙈" : "👁️"}
        </button>
      </div>

      <button className="home__btn home__btn--primary" type="button" onClick={handleRegister} style={{ marginTop: '10px', width: '100%', opacity: isSubmitting ? 0.7 : 1 }} disabled={isSubmitting}>
        {isSubmitting ? "Bilgiler İşleniyor..." : "Kayıt Ol"}
      </button>
    </div>
  );
};

export default Register;
