import React, { useState, useEffect } from 'react';
import { auth } from '../firebaseConfig';
import { confirmPasswordReset, verifyPasswordResetCode } from 'firebase/auth';

const ResetPassword = ({ oobCode, onBackToLogin, onEyeStateChange }) => {
  const [newPassword, setNewPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [message, setMessage] = useState({ text: '', type: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [resetEmail, setResetEmail] = useState(null);
  const [isValidating, setIsValidating] = useState(true);

  useEffect(() => {
    if (!oobCode) return;
    const checkCode = async () => {
      try {
        const email = await verifyPasswordResetCode(auth, oobCode);
        setResetEmail(email);
      } catch (error) {
        console.error("Link doğrulama hatası:", error.message);
        setMessage({ text: "Geçersiz veya süresi dolmuş bir bağlantı kullandınız.", type: "error" });
      } finally {
        setIsValidating(false);
      }
    };
    checkCode();
  }, [oobCode]);

  const handleConfirmReset = async (e) => {
    e.preventDefault();
    if (!oobCode || !newPassword) return;
    
    setIsSubmitting(true);
    setMessage({ text: '', type: '' });
    try {
      await confirmPasswordReset(auth, oobCode, newPassword);
      setMessage({ text: "Şifreniz başarıyla güncellendi! Artık yeni şifrenizle giriş yapabilirsiniz.", type: "success" });
    } catch (error) {
      console.error("Şifre güncelleme hatası:", error.message);
      setMessage({ text: "Bilinmeyen veya süresi dolmuş bir sıfırlama bağlantısı.", type: "error" });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleConfirmReset} style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
      <h2 style={{ fontFamily: "'Baloo 2', cursive", fontSize: '1.4rem', color: '#2d6e40', marginBottom: '2px' }}>Yeni Şifre Belirle</h2>
      
      {message.text && (
        <div style={{
          padding: '8px',
          marginBottom: '4px',
          borderRadius: '8px',
          fontSize: '0.85rem',
          textAlign: 'center',
          fontWeight: '700',
          backgroundColor: message.type === 'success' ? '#e8f5e9' : '#ffecec',
          color: message.type === 'success' ? '#2d6e40' : '#eb4d4b',
          border: `1px solid ${message.type === 'success' ? '#c8e6c9' : '#ffcdd2'}`
        }}>
          {message.text}
        </div>
      )}

      {message.type !== 'success' ? (
        isValidating ? (
          <div style={{ padding: '20px', textAlign: 'center', color: '#2d6e40', fontSize: '0.9rem', fontWeight: 'bold' }}>
            Bağlantı kontrol ediliyor...
          </div>
        ) : resetEmail ? (
          <>
            <div style={{ marginBottom: '8px', fontSize: '0.85rem', color: '#2d4a38', fontWeight: '700' }}>
              <span style={{opacity: 0.8}}>Hesap:</span> <br/>
              <span style={{ fontSize: '1rem', color: '#2d6e40' }}>{resetEmail}</span>
            </div>
            <div style={{ position: 'relative', width: '100%', marginBottom: '4px' }}>
              <input 
                className="modal__input"
                type={showPassword ? "text" : "password"}
                placeholder="Yeni Şifreniz" 
                value={newPassword} 
                onChange={(e) => setNewPassword(e.target.value)} 
                onFocus={() => { if (onEyeStateChange) onEyeStateChange(showPassword ? "peeking" : "closed"); }}
                onBlur={() => { if (onEyeStateChange) onEyeStateChange("open"); }}
                required 
                style={{ paddingRight: '45px', marginBottom: '0px' }}
              />
              <button
                type="button"
                onClick={() => {
                  const nextState = !showPassword;
                  setShowPassword(nextState);
                  if (onEyeStateChange) onEyeStateChange(nextState ? "peeking" : "closed");
                }}
                style={{
                  position: 'absolute',
                  right: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  cursor: 'pointer',
                  fontSize: '1.2rem',
                  padding: '2px',
                  opacity: 0.6,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}
                title={showPassword ? "Şifreyi Gizle" : "Şifreyi Göster"}
              >
                {showPassword ? "🙈" : "👁️"}
              </button>
            </div>
            <button className="home__btn home__btn--primary" type="submit" disabled={isSubmitting} style={{ marginTop: '4px', width: '100%', opacity: isSubmitting ? 0.7 : 1 }}>
              {isSubmitting ? "Güncelleniyor..." : "Şifreyi Güncelle"}
            </button>
          </>
        ) : null
      ) : (
        <button type="button" className="home__btn home__btn--secondary" onClick={onBackToLogin} style={{ marginTop: '10px', width: '100%' }}>
          Giriş Ekranına Dön
        </button>
      )}

      {message.type !== 'success' && (
        <button 
          type="button" 
          onClick={onBackToLogin}
          style={{ 
            marginTop: '8px', 
            backgroundColor: 'transparent', 
            color: '#2d6e40', 
            border: 'none', 
            cursor: 'pointer', 
            textDecoration: 'underline',
            fontSize: '1rem',
            fontFamily: "'Baloo 2', cursive",
            fontWeight: '600'
          }}
        >
          İptal ve Geri Dön
        </button>
      )}
    </form>
  );
};

export default ResetPassword;
