import React, { useState } from "react";
import { useApp } from "../context/AppContext";

export default function GameSingleConfigModal({ onClose }) {
  const { wordPairs, startGameSingleWithQueue } = useApp();
  const [tab, setTab] = useState("random"); // "random" | "select"
  const [selectedIds, setSelectedIds] = useState([]);

  const getRandomPairs = (arr, count) => {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, count);
  };

  const handleStart = () => {
    if (tab === "random") {
      const randomPairs = getRandomPairs(wordPairs, 10);
      startGameSingleWithQueue(randomPairs);
    } else {
      if (selectedIds.length === 0) return;
      const selectedPairs = selectedIds.map(id => wordPairs.find(p => p.id === id)).filter(Boolean);
      startGameSingleWithQueue(selectedPairs);
    }
  };

  const toggleSelect = (id) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ display: 'flex', flexDirection: 'column', height: tab === "select" ? '85vh' : 'auto' }}>
        <h2 className="modal__title" style={{ marginBottom: 16 }}>🎯 Dilim Nerede - Ayarlar</h2>
        
        <div style={{ display: "flex", gap: 8, marginBottom: 20 }}>
          <button 
            onClick={() => setTab("random")}
            style={{ flex: 1, padding: "10px", borderRadius: 12, border: "none", fontWeight: 800, background: tab === "random" ? "#2ecc71" : "#f0f4f1", color: tab === "random" ? "white" : "#5a9a6a", cursor: "pointer", transition: "all 0.2s" }}
          >
            🎲 Rastgele Mod
          </button>
          <button 
            onClick={() => setTab("select")}
            style={{ flex: 1, padding: "10px", borderRadius: 12, border: "none", fontWeight: 800, background: tab === "select" ? "#2ecc71" : "#f0f4f1", color: tab === "select" ? "white" : "#5a9a6a", cursor: "pointer", transition: "all 0.2s" }}
          >
            📝 Kelime Seç
          </button>
        </div>

        {tab === "random" ? (
          <div style={{ padding: "20px 0", textAlign: "center" }}>
            <p style={{ fontSize: "1.1rem", color: "#2d4a38", fontWeight: 700 }}>
              Kayıtlı tüm kelimeler arasından rastgele en fazla 10 adet kelime çifti seçilerek oyuna başlanacaktır.
            </p>
          </div>
        ) : (
          <div style={{ flex: 1, overflowY: "auto", paddingRight: 10, margin: "0 -10px 20px 0" }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              {wordPairs.map(pair => {
                const isSelected = selectedIds.includes(pair.id);
                return (
                  <div 
                    key={pair.id} 
                    onClick={() => toggleSelect(pair.id)}
                    style={{ 
                      padding: "10px", 
                      borderRadius: 12, 
                      border: `2px solid ${isSelected ? "#2ecc71" : "#d4eedd"}`,
                      background: isSelected ? "#eafaf1" : "#f6fdf8",
                      cursor: "pointer",
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center"
                    }}
                  >
                    <span style={{ fontWeight: 800, color: "#2d4a38" }}>{pair.word1} / {pair.word2}</span>
                    {isSelected && <span style={{ color: "#2ecc71" }}>✅</span>}
                  </div>
                )
              })}
            </div>
          </div>
        )}

        <div className="modal__actions" style={{ marginTop: "auto" }}>
          <button className="modal__btn modal__btn--cancel" onClick={onClose}>
            İptal
          </button>
          <button 
            className="modal__btn modal__btn--save" 
            onClick={handleStart}
            disabled={tab === "select" && selectedIds.length === 0}
            style={{ opacity: (tab === "select" && selectedIds.length === 0) ? 0.5 : 1 }}
          >
            ▶ Başla
          </button>
        </div>
      </div>
    </div>
  );
}
