import React from "react";
import ReactDOM from "react-dom/client";
import "./styles/global.css";
import App from "./App";
// import VConsole from 'vconsole';

// vConsole testlerini kapattık
// const vConsole = new VConsole();

// Firebase'in arka planda ürettiği zararsız AbortError'ları React'ın hata overlay'ine ulaşmadan yakala ve sustur.
// Bu hatalar Firebase Auth SDK'sının kendi iç network isteklerinden kaynaklanır, kullanıcı işlemini etkilemez.
const suppressAbortErrors = (event) => {
  if (
    event.reason instanceof Error && event.reason.name === 'AbortError' ||
    event.message && event.message.includes('AbortError') ||
    event.message && event.message.includes('user aborted')
  ) {
    event.preventDefault();
    event.stopImmediatePropagation();
    return false;
  }
};
window.addEventListener('unhandledrejection', suppressAbortErrors);
window.addEventListener('error', suppressAbortErrors);

const root = ReactDOM.createRoot(document.getElementById("root"));
// React.StrictMode kaldırıldı: Development modunda Firebase'i 2 kez çalıştırıp
// gereksiz AbortError üretmesini engeller.
root.render(<App />);
