// Tırtıl SVG'si için gradient ve filter tanımları
// Bu bileşen yalnızca <defs> bloğunu render eder;
// üst bileşen tarafından <svg> içinde kullanılmalıdır.

export default function CaterpillarDefs() {
  return (
    <defs>
      {/* ── Gövde Gradyanları ── */}
      <radialGradient id="c-seg" cx="35%" cy="25%" r="70%">
        <stop offset="0%"   stopColor="#f7c4b0" />
        <stop offset="50%"  stopColor="#eb9478" />
        <stop offset="100%" stopColor="#d4705a" />
      </radialGradient>

      <radialGradient id="c-segHi" cx="35%" cy="18%" r="52%">
        <stop offset="0%"   stopColor="#fde0d0" stopOpacity="0.85" />
        <stop offset="100%" stopColor="#fde0d0" stopOpacity="0" />
      </radialGradient>

      <radialGradient id="c-headGrad" cx="38%" cy="26%" r="68%">
        <stop offset="0%"   stopColor="#f8cebb" />
        <stop offset="50%"  stopColor="#eb9478" />
        <stop offset="100%" stopColor="#d4705a" />
      </radialGradient>

      {/* ── Neon Işık Filtreleri ── */}
      <filter id="c-glowF" x="-70%" y="-70%" width="240%" height="240%">
        <feGaussianBlur stdDeviation="12" result="b" />
        <feFlood floodColor="#ffd740" floodOpacity="0.9" result="c" />
        <feComposite in="c" in2="b" operator="in" result="g" />
        <feMerge><feMergeNode in="g" /><feMergeNode in="SourceGraphic" /></feMerge>
      </filter>

      <filter id="c-glowM" x="-70%" y="-70%" width="240%" height="240%">
        <feGaussianBlur stdDeviation="12" result="b" />
        <feFlood floodColor="#ff9f43" floodOpacity="0.9" result="c" />
        <feComposite in="c" in2="b" operator="in" result="g" />
        <feMerge><feMergeNode in="g" /><feMergeNode in="SourceGraphic" /></feMerge>
      </filter>

      <filter id="c-glowB" x="-70%" y="-70%" width="240%" height="240%">
        <feGaussianBlur stdDeviation="12" result="b" />
        <feFlood floodColor="#ee5a24" floodOpacity="0.9" result="c" />
        <feComposite in="c" in2="b" operator="in" result="g" />
        <feMerge><feMergeNode in="g" /><feMergeNode in="SourceGraphic" /></feMerge>
      </filter>

      {/* ── İç Lamba Gradyanları ── */}
      <radialGradient id="c-lampF" cx="50%" cy="50%" r="50%">
        <stop offset="0%"   stopColor="#fff9c4" stopOpacity="0.95" />
        <stop offset="55%"  stopColor="#ffd740" stopOpacity="0.6" />
        <stop offset="100%" stopColor="#ffd740" stopOpacity="0" />
      </radialGradient>

      <radialGradient id="c-lampM" cx="50%" cy="50%" r="50%">
        <stop offset="0%"   stopColor="#fff3e0" stopOpacity="0.95" />
        <stop offset="55%"  stopColor="#ff9f43" stopOpacity="0.6" />
        <stop offset="100%" stopColor="#ff9f43" stopOpacity="0" />
      </radialGradient>

      <radialGradient id="c-lampB" cx="50%" cy="50%" r="50%">
        <stop offset="0%"   stopColor="#ffe5e0" stopOpacity="0.95" />
        <stop offset="55%"  stopColor="#ee5a24" stopOpacity="0.6" />
        <stop offset="100%" stopColor="#ee5a24" stopOpacity="0" />
      </radialGradient>

      {/* ── Zemin Gölgesi ── */}
      <radialGradient id="c-shadowGrad" cx="50%" cy="50%" r="50%">
        <stop offset="0%"   stopColor="rgba(60,100,50,0.22)" />
        <stop offset="100%" stopColor="rgba(60,100,50,0)" />
      </radialGradient>
    </defs>
  );
}
