// Kelime Listesi ve Seçim Ekranı (Word List Screen)
// Terapist kelimeleri görür, seçim yapar, yeni kelime ekler
// ve seçilen kuyruğu ile oyunu başlatabilir.

import { useState } from "react";
import { useApp }   from "../context/AppContext";
import Background   from "../components/Background";
import AddWordModal from "../components/AddWordModal";

const POSITION_META = {
  front: { icon: "🌟", label: "Ön"   },
  back:  { icon: "🔆", label: "Arka" },
};

export default function WordList() {
  const {
    wordPairs,
    addWordPair,
    updateWordPair,
    deleteWordPair,
    goHome,
    startGameWithAll,
    startGameWithQueue,
  } = useApp();

  // Seçili kelime çiftlerinin ID dizisi (sıralı)
  const [selectedIds, setSelectedIds] = useState([]);
  const [showModal,   setShowModal]   = useState(false);
  const [editingPair, setEditingPair] = useState(null);

  // Bir kartın seçim durumunu toggle et
  const toggleSelect = (id) => {
    setSelectedIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  // Seçim sırası numarası (1-based), seçili değilse null
  const orderOf = (id) => {
    const idx = selectedIds.indexOf(id);
    return idx >= 0 ? idx + 1 : null;
  };

  // Seçilenlerle oyunu başlat
  const handleStartSelected = () => {
    const queue = selectedIds.map((id) => wordPairs.find((p) => p.id === id)).filter(Boolean);
    startGameWithQueue(queue);
  };

  // Silme butonu tıklaması kartın seçimini tetiklememeli
  const handleDelete = (e, id) => {
    e.stopPropagation();
    setSelectedIds((prev) => prev.filter((x) => x !== id));
    deleteWordPair(id);
  };

  const handleEdit = (e, pair) => {
    e.stopPropagation();
    setEditingPair(pair);
    setShowModal(true);
  };

  return (
    <div className="screen">
      <Background />

      {/* Header */}
      <div className="lk-header">
        <button className="lk-back-btn" onClick={goHome}>← Geri</button>
        <span className="lk-header__title">📋 Kelime Listesi</span>
        <div style={{ width: 64 }} /> {/* sağ boşluk dengeleyici */}
      </div>

      {/* Gövde */}
      <div className="wordlist__body">
        {/* Araç çubuğu */}
        <div className="wordlist__toolbar">
          <span className="wordlist__count">
            {wordPairs.length} kelime çifti
            {selectedIds.length > 0 && ` · ${selectedIds.length} seçili`}
          </span>
          <button className="wordlist__add-btn" onClick={() => setShowModal(true)}>
            ➕ Ekle
          </button>
        </div>

        {/* Kelime çifti ızgarası */}
        <div className="wordlist__grid">
          {wordPairs.map((pair) => {
            const isSelected = selectedIds.includes(pair.id);
            const order      = orderOf(pair.id);
            const pos1 = pair.position1 || pair.position || "front";
            const pos2 = pair.position2 || pair.position || "front";
            const meta1 = POSITION_META[pos1] || POSITION_META.front;
            const meta2 = POSITION_META[pos2] || POSITION_META.front;

            return (
              <div
                key={pair.id}
                className={`wp-card${isSelected ? " selected" : ""}`}
                onClick={() => toggleSelect(pair.id)}
              >
                {/* Seçim sırası rozeti */}
                {order && <div className="wp-card__order">{order}</div>}

                {/* Pozisyon ikonları */}
                <div style={{ display: 'flex', gap: '4px', flexDirection: 'column' }}>
                  <div className={`wp-card__badge wp-card__badge--${pos1}`} style={{ height: '30px' }} title="1. Kelime">
                    {meta1.icon}
                  </div>
                  <div className={`wp-card__badge wp-card__badge--${pos2}`} style={{ height: '30px' }} title="2. Kelime">
                    {meta2.icon}
                  </div>
                </div>

                {/* Kelimeler */}
                <div className="wp-card__words">
                  <span className="wp-card__pair">
                    {pair.word1} &nbsp;/&nbsp; {pair.word2}
                  </span>
                  <span className="wp-card__pos">{meta1.label} / {meta2.label} Pozisyon</span>
                </div>

                {/* Sil ve Düzenle butonları */}
                <div style={{ display: "flex", gap: "8px", position: "absolute", top: "12px", right: "12px", zIndex: 2 }}>
                  <button
                    className="wp-card__delete"
                    style={{ position: "relative", top: "0", right: "0" }}
                    onClick={(e) => handleEdit(e, pair)}
                    title="Düzenle"
                  >
                    ✏️
                  </button>
                  <button
                    className="wp-card__delete"
                    style={{ position: "relative", top: "0", right: "0" }}
                    onClick={(e) => handleDelete(e, pair.id)}
                    title="Sil"
                  >
                    🗑
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Alt aksiyon çubuğu */}
      <div className="wordlist__action-bar">
        <button
          className="wordlist__start-btn wordlist__start-btn--all"
          onClick={startGameWithAll}
        >
          ▶ Tümüyle Başla
        </button>
        <button
          className="wordlist__start-btn wordlist__start-btn--selected"
          onClick={handleStartSelected}
          disabled={selectedIds.length === 0}
        >
          ✅ Seçilenlerle Başla ({selectedIds.length})
        </button>
      </div>

      {/* Modal */}
      {showModal && (
        <AddWordModal
          initialData={editingPair}
          onClose={() => {
            setShowModal(false);
            setEditingPair(null);
          }}
          onSave={(data) => {
            if (editingPair) {
              updateWordPair(editingPair.id, data);
            } else {
              addWordPair(data);
            }
          }}
        />
      )}
    </div>
  );
}
