import React, { useState } from 'react';
import { auth } from '../firebaseConfig';
import { signInWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';

const Login = ({ onEyeStateChange }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [message, setMessage] = useState({ text: '', type: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);

  const handleLogin = async (e) => {
    if (e) e.preventDefault();
    setMessage({ text: '', type: '' });
    setIsSubmitting(true);
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      console.log("Giriş yapıldı:", userCredential.user);
    } catch (error) {
      console.error("Giriş hatası:", error.message);
      setMessage({ text: "Giriş başarısız. Lütfen bilgilerinizi kontrol edin.", type: "error" });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResetPassword = async () => {
    // Kullanıcı e-posta kutusunu boş bıraktıysa uyar
    if (!email) {
      setMessage({ text: "Lütfen şifrenizi sıfırlamak için önce e-posta alanını doldurun.", type: "error" });
      return;
    }

    // İstek başladı, butonu kilitle
    setIsResetting(true); 
    setMessage({ text: '', type: '' });

    try {
      // E-posta input'una girilen değeri Firebase'e gönder
      await sendPasswordResetEmail(auth, email);
      setMessage({ 
        text: "Şifre sıfırlama bağlantısı e-posta adresinize gönderildi! (Spam kutusunu kontrol etmeyi unutmayın)", 
        type: "success" 
      });
    } catch (error) {
      console.error("Şifre sıfırlama hatası:", error.message);
      setMessage({ text: "Hata: " + error.message, type: "error" });
    } finally {
      // İşlem başarılı da olsa hatalı da olsa kilidi kaldır
      setIsResetting(false); 
    }
  };

  return (
    <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
        <h2 style={{ fontFamily: "'Baloo 2', cursive", fontSize: '1.4rem', color: '#2d6e40', marginBottom: '2px' }}>Giriş Yap</h2>

        {message.text && (
          <div style={{
            padding: '8px',
            marginBottom: '4px',
            borderRadius: '8px',
            fontSize: '0.85rem',
            textAlign: 'center',
            fontWeight: '700',
            backgroundColor: message.type === 'success' ? '#e8f5e9' : '#ffecec',
            color: message.type === 'success' ? '#2d6e40' : '#eb4d4b',
            border: `1px solid ${message.type === 'success' ? '#c8e6c9' : '#ffcdd2'}`
          }}>
            {message.text}
          </div>
        )}

        <input
          className="modal__input"
          type="email"
          placeholder="E-posta Adresi"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          onFocus={() => { if (onEyeStateChange) onEyeStateChange("open"); }}
          required
        />

        <div style={{ position: 'relative', width: '100%' }}>
          <input
            className="modal__input"
            type={showPassword ? "text" : "password"}
            placeholder="Şifre"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onFocus={() => { if (onEyeStateChange) onEyeStateChange(showPassword ? "peeking" : "closed"); }}
            onBlur={() => { if (onEyeStateChange) onEyeStateChange("open"); }}
            required
            style={{ paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => {
              const nextState = !showPassword;
              setShowPassword(nextState);
              if (onEyeStateChange) onEyeStateChange(nextState ? "peeking" : "closed");
            }}
            style={{
              position: 'absolute',
              right: '12px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              fontSize: '1.2rem',
              padding: '2px',
              opacity: 0.6,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
            title={showPassword ? "Şifreyi Gizle" : "Şifreyi Göster"}
          >
            {showPassword ? "🙈" : "👁️"}
          </button>
        </div>

        <button className="home__btn home__btn--primary" type="submit" style={{ marginTop: '4px', width: '100%' }}>
          Giriş Yap
        </button>

        {/* Şifremi Unuttum Butonu */}
        <button 
          type="button" 
          onClick={handleResetPassword}
          disabled={isResetting}
          style={{ 
            marginTop: '0px', 
            backgroundColor: 'transparent', 
            color: isResetting ? 'gray' : '#2d6e40', 
            border: 'none', 
            cursor: isResetting ? 'not-allowed' : 'pointer', 
            textDecoration: 'underline',
            fontSize: '1rem',
            fontFamily: "'Baloo 2', cursive",
            fontWeight: '600'
          }}
        >
          {isResetting ? "Gönderiliyor..." : "Şifremi Unuttum"}
        </button>
      </form>
  );
};

export default Login;
